import{_ as o,c as l,o as r,a5 as i,j as a}from"./chunks/framework.Dtwt352Q.js";const k=JSON.parse('{"title":"v1.1.65：Tool Definition Hook","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.65.md","filePath":"changelog/v1.1.65.md","lastUpdated":1772014034000}'),t={name:"changelog/v1.1.65.md"};function n(d,e,h,s,c,p){return r(),l("div",null,[...e[0]||(e[0]=[i('<h1 id="v1-1-65-tool-definition-hook" tabindex="-1">v1.1.65：Tool Definition Hook <a class="header-anchor" href="#v1-1-65-tool-definition-hook" aria-label="Permalink to “v1.1.65：Tool Definition Hook”">​</a></h1><p><strong>发布日期</strong>：2026年2月13日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新为插件添加了 <strong>tool.definition Hook</strong>，可以修改工具描述和参数，同时修复了 Windows ACP 卡死、桌面端多项问题。</p><hr><h2 id="新功能-tool-definition-hook" tabindex="-1">新功能：Tool Definition Hook <a class="header-anchor" href="#新功能-tool-definition-hook" aria-label="Permalink to “新功能：Tool Definition Hook”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>插件现在可以使用 <strong>tool.definition Hook</strong> 来修改工具的描述和参数。</p><h3 id="这是什么" tabindex="-1">这是什么？ <a class="header-anchor" href="#这是什么" aria-label="Permalink to “这是什么？”">​</a></h3><p>Hook 是插件的扩展点。通过这个新 Hook，插件可以：</p><ul><li>修改工具的描述文字</li><li>调整工具的参数定义</li><li>自定义工具的显示方式</li></ul><h3 id="应用场景" tabindex="-1">应用场景 <a class="header-anchor" href="#应用场景" aria-label="Permalink to “应用场景”">​</a></h3><ul><li>为特定工具添加自定义提示</li><li>隐藏不需要的工具参数</li><li>调整工具的默认行为说明</li></ul><hr><h2 id="改进-目录-使用-read-工具" tabindex="-1">改进：@目录 使用 Read 工具 <a class="header-anchor" href="#改进-目录-使用-read-工具" aria-label="Permalink to “改进：@目录 使用 Read 工具”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>当你在对话中 @ 一个目录时，OpenCode 现在使用 <strong>Read 工具而不是已弃用的 List 工具</strong>。</p><h3 id="好处是什么" tabindex="-1">好处是什么？ <a class="header-anchor" href="#好处是什么" aria-label="Permalink to “好处是什么？”">​</a></h3><ul><li>获取更完整的目录信息</li><li>行为更一致</li><li>为未来移除 List 工具做准备</li></ul><hr><h2 id="问题修复-windows-acp-卡死" tabindex="-1">问题修复：Windows ACP 卡死 <a class="header-anchor" href="#问题修复-windows-acp-卡死" aria-label="Permalink to “问题修复：Windows ACP 卡死”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>在 Windows 上，ACP（Agent Communication Protocol）有时会无限期卡在思考状态。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>修复了这个问题，Windows 上不会再卡死了。</p><hr><h2 id="改进-桌面端" tabindex="-1">改进：桌面端 <a class="header-anchor" href="#改进-桌面端" aria-label="Permalink to “改进：桌面端”">​</a></h2><h3 id="事件流重连" tabindex="-1">事件流重连 <a class="header-anchor" href="#事件流重连" aria-label="Permalink to “事件流重连”">​</a></h3><p>桌面应用断开连接后会自动重连事件流，更稳定。</p><h3 id="批量切换模型" tabindex="-1">批量切换模型 <a class="header-anchor" href="#批量切换模型" aria-label="Permalink to “批量切换模型”">​</a></h3><p>设置中可以 <strong>一次性切换所有提供商的模型</strong>，不用逐个切换。</p><h3 id="加载页面优化" tabindex="-1">加载页面优化 <a class="header-anchor" href="#加载页面优化" aria-label="Permalink to “加载页面优化”">​</a></h3><p>优化了桌面加载页面，只在需要 SQLite 迁移时才显示加载窗口。</p><h3 id="通知导航" tabindex="-1">通知导航 <a class="header-anchor" href="#通知导航" aria-label="Permalink to “通知导航”">​</a></h3><p>点击通知会直接导航到对应会话。</p><h3 id="输入框修复" tabindex="-1">输入框修复 <a class="header-anchor" href="#输入框修复" aria-label="Permalink to “输入框修复”">​</a></h3><p>修复了提示输入框的一些行为问题。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>开发插件</td><td>✅ 升级</td></tr><tr><td>Windows 用户</td><td>✅ 强烈推荐</td></tr><tr><td>使用桌面版</td><td>✅ 升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',42),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),i('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-核心" tabindex="-1">Core（核心） <a class="header-anchor" href="#core-核心" aria-label="Permalink to “Core（核心）”">​</a></h3><ul><li>回退 OPENCODE_CONFIG_CONTENT 中的 token 替换</li><li>@目录 使用 Read 工具而非已弃用的 List 工具</li><li>添加 tool.definition Hook，允许插件修改工具描述和参数</li><li>移除 worktree 删除功能</li><li>解决 Windows 上 ACP 无限期卡在思考状态的问题</li></ul><h3 id="desktop-桌面应用" tabindex="-1">Desktop（桌面应用） <a class="header-anchor" href="#desktop-桌面应用" aria-label="Permalink to “Desktop（桌面应用）”">​</a></h3><ul><li>断开连接时重连事件流</li><li>设置中批量切换所有提供商模型</li><li>清理桌面加载页面</li><li>通知点击导航到会话</li><li>修复提示输入框行为问题</li><li>修复应用中创建 store 失败</li><li>只在需要 SQLite 迁移时显示加载窗口</li></ul><h3 id="社区贡献" tabindex="-1">社区贡献 <a class="header-anchor" href="#社区贡献" aria-label="Permalink to “社区贡献”">​</a></h3><ul><li>@spoons-and-mirrors：添加 tool.definition Hook</li><li>@ASidorenkoCode：修复 Windows ACP 卡死问题</li><li>@Brendonovich：桌面端多项优化（加载页面、SQLite 迁移检测）</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const f=o(t,[["render",n]]);export{k as __pageData,f as default};
